        LinearizedValue := 150.0;
        Error := TRUE;
        Status := 16#8001;
        state := 0; // Return to initialization state

    5: // Above maximum range
        LinearizedValue := 720.0;
        Error := TRUE;
        Status := 16#8001;
        state := 0; // Return to initialization state

    ELSE
        // Default case, should not occur
        LinearizedValue := 0.0;
        Error := TRUE;
        Status := 16#FFFF; // Undefined state error
        state := 0; // Return to initialization state
END_CASE;

