    0: (* IDLE state *)
        WaterHeating := FALSE;
        GrinderRunning := FALSE;
        Brewing := FALSE;
        WaterHeated := FALSE;
        GrinderFinished := FALSE;
        CoffeeReady := FALSE;

        IF StartButton AND NOT WaterHeated THEN
            state := 1; (* Transition to WATER HEATING state *)
