        WaterHeating := TRUE;
        GrinderRunning := FALSE;
        Brewing := FALSE;
        WaterHeated := FALSE;
        GrinderFinished := FALSE;
        CoffeeReady := FALSE;

        IF ElapsedTime >= WaterHeatingDuration THEN
            WaterHeated := TRUE;
            WaterHeating := FALSE;
            state := 2; (* Transition to GRINDING state *)
        END_IF;

        IF NOT StartButton THEN
            state := 0; (* Transition back to IDLE state *)
        END_IF;

