    MotorMovingUp := TRUE;
    MotorMovingDown := FALSE;
    DoorIsOpen := FALSE;
    MotorStationary := FALSE;

    // Transition to IDLE when the requested floor is reached
    IF CurrentPos = RequestedPos THEN
        state := 0; // Transition to IDLE
    END_IF;

