    ActivationTimer : INT := 0; (* Timer for activation duration *)
    MAX_ACTIVATION_TIME : INT := 300; (* Maximum activation time in seconds *)
END_VAR

(* State Definitions *)
(* STATE 0: IDLE *)
(* STATE 1: ACTIVATION *)
(* STATE 2: MAINTAIN ACTIVATION *)
