    (* ACTIVATION State *)
    LightingControl := TRUE;
    AudioControl := TRUE;
    VisualControl := TRUE;
    ActivationTimer := ActivationTimer + 1;

    (* Transition to MAINTAIN ACTIVATION State *)
    IF MotionSensor = TRUE AND ActivationTimer < MAX_ACTIVATION_TIME THEN
